INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-d1056197-moex-00162', 'promotion-d1056197', 'promotion-d1056197-moex-110-3082b5f1', 'sub-promotion-d1056197-02', NULL, 'single_choice', '甲所有的部分土地長期供公眾通行使用，鄉公所並鋪設柏油道路，設置路燈及負責道路修繕。經 過數十年鄰地的聯外道路系統已相當發達，已少有公眾使用該既成道路。甲希望能使用供公眾使 用既成道路的土地，擬向行政法院提起訴訟恢復既成道路上土地得自由使用收益狀態。甲應提起 下列何種行政訴訟？', '["撤銷之訴", "一般給付之訴", "所有權返還之訴", "確認公法法律關係存否之訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "135", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('promotion-d1056197-moex-00163', 'promotion-d1056197', 'promotion-d1056197-moex-110-3082b5f1', 'sub-promotion-d1056197-02', NULL, 'single_choice', '甲市政府基於成本考量將該市所興建所有的焚化爐，委託乙公司運作經營。由於乙公司人員操作 焚化爐不當，釋放大量戴奧辛等有毒氣體致周邊居民吸入後產生健康的危害。請問受害居民應如 何求償，以下敘述何者正確？', '["甲市政府既已將焚化爐委託乙公司經營管理，受害居民僅能向乙公司行使民事侵權行為之損害 賠償，國家並無責任", "受害人民仍得以甲市政府為賠償義務機關提起國家賠償之訴，不論該焚化爐是否已經委託乙公 司經營管理", "受害人民對於其身體健康的損害，必須證明乙公司人員操作焚化爐有過失，始能請求國家賠償", "受害人民對於身體健康之損害，僅能擇一向乙公司提起民事損害賠償之訴，或以甲市政府為賠 償義務機關提起國家賠償之訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "135", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('promotion-d1056197-moex-00164', 'promotion-d1056197', 'promotion-d1056197-moex-110-3082b5f1', 'sub-promotion-d1056197-02', NULL, 'single_choice', '駕駛人於路邊停車格內停車，主管機關因該處地層下陷，緊急遂請拖吊業者將其車移至適當地點。 駕駛人事後發覺車輛因移置而受有損害。其可提出何種救濟？', '["向法院提起國家賠償", "向主管機關提起民事損害賠償", "向拖吊業者提起民事損害賠償", "向主管機關請求損失補償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "135", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00001', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-3a1cfc18', 'sub-promotion-d592fc58-01', NULL, 'essay', 'A為公開發行股票之股份有限公司，召開年度股東常會，召集通知及公
告上記載召集權人為董事長甲，召集事由為修改公司章程第○條，並未
記載有臨時動議之議程。然於股東會進行時，股東乙提出臨時動議，並
提案「解任甲董事」，主席裁定以舉手表決方法作成「解任甲董事」之決
議。試問：上述股東會會議中有那些瑕疵？請附具理由說明之。（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:36+00:00", "source_pdf_sha1": "03237c5b843f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0514", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公司法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00002', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-3a1cfc18', 'sub-promotion-d592fc58-01', NULL, 'essay', '大大股份有限公司有股東 5人 ABCDE，其中 CDE為自然人股東，A為
法人股東，其自然人代表為甲，B 為政府股東，自然人代表為乙、丙，
請回答下列問題：（每小題 10分，共 30分）
B股東其自然人代表乙、丙分別被選為大大公司之董事及監察人，是
否合法？
甲以自己名義被選為大大公司之董事後，因為突然心肌梗塞過世，A
可否因而另行改派丁為董事？
B股東其自然人代表乙被選為大大公司之董事後，乙被大大公司之股
東會解任後，B可否改派丙繼任之？', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:36+00:00", "source_pdf_sha1": "03237c5b843f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0514", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公司法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00003', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-3a1cfc18', 'sub-promotion-d592fc58-01', NULL, 'essay', '甲、乙、丙三位好友相約一同創業，每人各出資新臺幣（下同）15 萬元
投資籌組設立「A餐飲有限公司」（以下簡稱 A公司），而三人約定，在
公司未來成立後將由甲擔任董事。公司在籌設時，甲以 A公司名義和房
東丁訂立租賃契約，承租臺北市一樓房屋，作為公司將來成立後之辦公
場所。另外為了籌設公司，已經有 3 萬元之各項費用應支付（如水、電、
電話費、影印費、車馬費等），惟 A 公司後來因故未能登記成立。上述
租賃契約以及3萬元的支出應由何人負責？試附理由回答之。（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:36+00:00", "source_pdf_sha1": "03237c5b843f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0514", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公司法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00004', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-3a1cfc18', 'sub-promotion-d592fc58-01', NULL, 'essay', '甲為 A公司之資深員工，後經拔擢為總經理，且經常代理 A公司簽約。
甲以 A公司名義向銀行借款新臺幣 200萬元做為自己購屋之頭期款，請
問此項貸款，銀行得否向 A公司主張？（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:36+00:00", "source_pdf_sha1": "03237c5b843f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0514", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公司法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00005', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'essay', '乙竊占甲所有之A地，而將之出租予丙，丙乃不知乙非 A地所有權人之
事實。乙與丙約定租金每年新臺幣 200萬元。丙在 A地上種植蘋果樹，
三年後結實纍纍。於蘋果即將收成之際，甲竟出現在丙之面前，並向丙
主張 A地上收成之蘋果皆屬甲之所有。丙十分錯愕！
試問，甲與乙間；甲與丙間；乙與丙間之法律關係各如何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00006', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'essay', '乙向甲承租甲所有之 A地，租金每月新臺幣（下同）10 萬元。乙在徵得
甲之同意下，乃以其自己之名義召請丙，擬在 A地上搭建一間溫室，以
便栽種溫室栽培作物。
稍後，因 A地地質之因素，丙雖耗盡一切努力，該溫室終究無法搭建完
成。惟丙仍向乙請求 100 萬元之工程款。蓋丙表示，於施工前丙業已告
知乙A地地質之相關缺陷。乙則轉而向甲請求償還該100萬元之工程款。
試問，乙與丙間；甲與乙間之法律關係各如何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00007', 'promotion-d592fc58', 'promotion-d592fc58-moex-114-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '甲女於滿16歲生日，收到20歲大學生乙男贈送之H手機。3日後，甲將未拆封之H，以新臺幣 4萬元出售並交付於23歲丙。下列關於贈與契約與所有權之敘述，何者正確？', '["甲、乙間H手機贈與契約，不生效力", "甲未曾取得H手機之所有權", "丙尚未取得H手機之所有權", "甲、丙間H手機買賣契約，有效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:37+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL)
